import React from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import Sidebar from '../components/Sidebar'
import ListingCard from '../components/ListingCard'

const ShopContentWrapper = styled.div `
width:80%;
margin:40px auto;
display:flex;

`

const SidebarWrapper = styled.div `
width:250px;
position:fixed;
height:300px;
overflow:scroll;
`

const Listings = styled.div `
width:1000px;
display:flex;
flex-wrap: wrap;
justify-content: center;
position:fixed;
height:300px;
overflow:scroll;
margin-left:200px;
`

export default function Me () {
	return (
		<>
			<Header />
			<Navbar />
			<ShopContentWrapper>
				<SidebarWrapper>
					<Sidebar />
				</SidebarWrapper>
				<Listings>
					<ListingCard />
					<ListingCard />
					<ListingCard />
					<ListingCard />
					<ListingCard />
					<ListingCard />
					<ListingCard />
					<ListingCard />
					<ListingCard />
